uint32_t Assets::CalculateChecksum(const char *data, uint32_t length)
{
    uint32_t checksum = 0;
    for (uint32_t i = 0; i < length; i++)
    {
        checksum += static_cast<uint8_t>(data[i]);
    }
    return checksum;
}

bool Assets::InitializePartition()
{
    // Step 1: Locate the assets partition
    partition_ = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_ANY, "assets");
    if (partition_ == nullptr) {
        ESP_LOGE(TAG, "Assets partition not found");
        return false;
    }

    ESP_LOGI(TAG, "Found assets partition: offset=0x%x, size=%d", partition_->address, partition_->size);

    // Step 2: Unmap previous mapping if any
    if (mmap_handle_ != 0) {
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
    }

    // Step 3: Map the entire partition into memory
    esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, SPI_FLASH_MMAP_DATA, &mmap_root_, &mmap_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        return false;
    }

    const char* mapped_data = static_cast<const char*>(mmap_root_);

    // Step 4: Parse the asset table
    assets_.clear();

    // Assume first 4 bytes contain the number of assets
    if (partition_->size < sizeof(uint32_t)) {
        ESP_LOGE(TAG, "Partition too small to hold asset table header");
        return false;
    }

    uint32_t num_assets = *reinterpret_cast<const uint32_t*>(mapped_data);
    size_t offset = sizeof(uint32_t);

    ESP_LOGD(TAG, "Number of assets in partition: %u", num_assets);

    // Check enough space left for asset table
    size_t table_size = num_assets * sizeof(struct mmap_assets_table);
    if ((offset + table_size + sizeof(uint32_t)) > partition_->size) { // +4 for checksum
        ESP_LOGE(TAG, "Partition too small for asset table and checksum");
        return false;
    }

    const struct mmap_assets_table* table = reinterpret_cast<const struct mmap_assets_table*>(mapped_data + offset);
    offset += table_size;

    // Populate assets map
    for (uint32_t i = 0; i < num_assets; ++i) {
        AssetInfo info{};
        info.offset = table[i].asset_offset;
        info.size = table[i].asset_size;
        info.width = table[i].asset_width;
        info.height = table[i].asset_height;

        std::string name(table[i].asset_name);
        assets_[name] = info;

        ESP_LOGD(TAG, "Loaded asset '%s': offset=0x%x, size=%u", name.c_str(), info.offset, info.size);
    }

    // Optional: Validate checksum
    uint32_t stored_checksum = *reinterpret_cast<const uint32_t*>(mapped_data + offset);
    uint32_t computed_checksum = CalculateChecksum(mapped_data, offset);

    if (stored_checksum != computed_checksum) {
        ESP_LOGE(TAG, "Checksum mismatch: stored=0x%04X, computed=0x%04X", stored_checksum, computed_checksum);
        checksum_valid_ = false;
        return false;
    } else {
        ESP_LOGI(TAG, "Assets checksum validated successfully.");
        checksum_valid_ = true;
    }

    return true;
}

