bool Assets::GetAssetData(const std::string &name, void *&ptr, size_t &size)
{
    if (!partition_valid_ || !checksum_valid_)
    {
        ESP_LOGE(TAG, "Assets partition is not valid or checksum failed");
        return false;
    }

    auto it = assets_.find(name);
    if (it == assets_.end())
    {
        ESP_LOGD(TAG, "Asset '%s' not found", name.c_str());
        return false;
    }

    const Asset &asset = it->second;

    // Validate asset bounds
    if (asset.offset + asset.size > partition_->size)
    {
        ESP_LOGE(TAG, "Asset '%s' extends beyond partition boundaries", name.c_str());
        return false;
    }

    ptr = const_cast<void*>(static_cast<const void*>(mmap_root_ + asset.offset));
    size = asset.size;

    return true;
}

