esp_err_t Ota::CheckVersion()
{
    std::string url = GetCheckVersionUrl();
    if (url.empty()) {
        ESP_LOGE(TAG, "OTA URL is empty");
        return ESP_FAIL;
    }

    auto http = SetupHttp();
    if (!http) {
        ESP_LOGE(TAG, "Failed to setup HTTP client");
        return ESP_FAIL;
    }

    // Prepare JSON payload
    cJSON *root = cJSON_CreateObject();
    cJSON_AddStringToObject(root, "version", current_version_.c_str());
    cJSON_AddStringToObject(root, "chip", SystemInfo::GetChipModel().c_str());
    cJSON_AddStringToObject(root, "board", SystemInfo::GetBoardName().c_str());

    if (has_serial_number_) {
        cJSON_AddStringToObject(root, "sn", serial_number_.c_str());
    }

    char mac_str[18] = {0};
    uint8_t mac[6];
    esp_read_mac(mac, ESP_MAC_WIFI_STA);
    snprintf(mac_str, sizeof(mac_str), "%02X:%02X:%02X:%02X:%02X:%02X",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
    cJSON_AddStringToObject(root, "mac", mac_str);

    char *json_string = cJSON_PrintUnformatted(root);
    std::string payload(json_string);
    cJSON_free(json_string);
    cJSON_Delete(root);

    http->SetContent(std::move(payload));

    if (!http->Open("POST", url)) {
        ESP_LOGE(TAG, "Failed to open HTTP connection to %s", url.c_str());
        return ESP_FAIL;
    }

    if (http->GetStatusCode() != 200) {
        ESP_LOGE(TAG, "HTTP request failed with status %d", http->GetStatusCode());
        return ESP_FAIL;
    }

    std::string response = http->ReadAll();
    if (response.empty()) {
        ESP_LOGE(TAG, "Empty response from server");
        return ESP_FAIL;
    }

    cJSON *json = cJSON_Parse(response.c_str());
    if (!json) {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_FAIL;
    }

    // Process server time
    cJSON *server_time = cJSON_GetObjectItem(json, "server_time");
    if (cJSON_IsObject(server_time)) {
        cJSON *timestamp = cJSON_GetObjectItem(server_time, "timestamp");
        cJSON *timezone_offset = cJSON_GetObjectItem(server_time, "timezone_offset");

        if (cJSON_IsNumber(timestamp)) {
            struct timeval tv;
            double ts = timestamp->valuedouble;

            // Apply timezone offset if available
            if (cJSON_IsNumber(timezone_offset)) {
                ts += (timezone_offset->valueint * 60 * 1000); // Convert minutes to milliseconds
            }

            tv.tv_sec = (time_t)(ts / 1000);                          // Convert milliseconds to seconds
            tv.tv_usec = (suseconds_t)((long long)ts % 1000) * 1000; // Remaining milliseconds to microseconds
            settimeofday(&tv, NULL);
            has_server_time_ = true;
            ESP_LOGI(TAG, "System time updated from server");
        }
    } else {
        ESP_LOGW(TAG, "No server_time section found in response");
    }

    // Check for firmware updates
    has_new_version_ = false;
    cJSON *firmware = cJSON_GetObjectItem(json, "firmware");
    if (cJSON_IsObject(firmware)) {
        cJSON *version = cJSON_GetObjectItem(firmware, "version");
        cJSON *url_item = cJSON_GetObjectItem(firmware, "url");

        if (cJSON_IsString(version) && cJSON_IsString(url_item)) {
            firmware_version_ = std::string(version->valuestring);
            firmware_url_ = std::string(url_item->valuestring);

            // Check if new version is available
            has_new_version_ = IsNewVersionAvailable(current_version_, firmware_version_);

            // Force update if specified
            cJSON *force = cJSON_GetObjectItem(firmware, "force");
            if (cJSON_IsNumber(force) && force->valueint == 1) {
                has_new_version_ = true;
                ESP_LOGI(TAG, "Forced update detected for version: %s", firmware_version_.c_str());
            } else if (has_new_version_) {
                ESP_LOGI(TAG, "New version available: %s", firmware_version_.c_str());
            } else {
                ESP_LOGI(TAG, "Current version is up to date");
            }
        } else {
            ESP_LOGW(TAG, "Invalid firmware object in response");
        }
    } else {
        ESP_LOGW(TAG, "No firmware section found in response");
    }

    // Check for activation challenge
    cJSON *activation = cJSON_GetObjectItem(json, "activation");
    if (cJSON_IsObject(activation)) {
        cJSON *challenge = cJSON_GetObjectItem(activation, "challenge");
        if (cJSON_IsString(challenge)) {
            activation_challenge_ = std::string(challenge->valuestring);
            has_activation_challenge_ = true;
            ESP_LOGI(TAG, "Received activation challenge");
        }
    }

    cJSON_Delete(json);
    return ESP_OK;
}

void Ota::MarkCurrentVersionValid()
{
    const esp_partition_t* partition = esp_ota_get_running_partition();
    if (partition == nullptr) {
        ESP_LOGE(TAG, "Failed to get running partition");
        return;
    }

    // Skip if we are running from factory partition
    if (strcmp(partition->label, "factory") == 0) {
        ESP_LOGI(TAG, "Running from factory partition, skipping validation");
        return;
    }

    ESP_LOGI(TAG, "Running partition: %s", partition->label);

    esp_ota_img_states_t state;
    esp_err_t err = esp_ota_get_state_partition(partition, &state);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to get state of partition: %s", esp_err_to_name(err));
        return;
    }

    if (state == ESP_OTA_IMG_PENDING_VERIFY) {
        ESP_LOGI(TAG, "Marking current firmware as valid");
        esp_err_t result = esp_ota_mark_app_valid_cancel_rollback();
        if (result != ESP_OK) {
            ESP_LOGE(TAG, "Failed to mark app as valid: %s", esp_err_to_name(result));
        } else {
            ESP_LOGI(TAG, "Firmware validated successfully");
        }
    } else {
        ESP_LOGI(TAG, "No need to validate firmware; current state: %d", state);
    }
}

