Based on the context and typical OTA (Over-The-Air) update workflows for ESP-IDF/ESP32 systems, this function should perform the following tasks:

1. **Validate Input**: Ensure that the firmware URL is valid.
2. **Initialize OTA Update Sequence**:
   - Begin an OTA update using `esp_ota_begin()`.
   - Select the next bootable partition (usually the OTA partition).
3. **Download Firmware via HTTP(S)**:
   - Use the existing HTTP client abstraction (`Http`) or similar mechanism to download chunks of data from the given URL.
4. **Write Data to Partition**:
   - Write each downloaded chunk to the target partition using `esp_ota_write()`.
5. **Track Progress**:
   - Optionally calculate transfer speed and call the provided `callback(progress, speed)` periodically during the download/write process.
6. **Finalize OTA Process**:
   - On success: Call `esp_ota_end()` and set the new partition as bootable with `esp_ota_set_boot_partition()`.
   - On failure: Abort OTA with `esp_ota_abort()` and log errors.
7. **Return Status**:
   - Return `true` on successful completion, otherwise `false`.

---

### Implementation Plan

We will implement the function by:
- Using the same `Http` class used elsewhere in the file.
- Handling large downloads with streaming read instead of loading all into memory.
- Calculating progress percentage and rough speed estimation.
- Proper error handling at every step.

---

Here's the completed implementation:

```cpp
bool Ota::Upgrade(const std::string &firmware_url, std::function<void(int progress, size_t speed)> callback)
{
    if (firmware_url.empty()) {
        ESP_LOGE(TAG, "Invalid firmware URL");
        return false;
    }

    const esp_partition_t* update_partition = esp_ota_get_next_update_partition(NULL);
    if (!update_partition) {
        ESP_LOGE(TAG, "Failed to get next update partition");
        return false;
    }

    ESP_LOGI(TAG, "Writing to partition subtype %d at offset 0x%x", update_partition->subtype, update_partition->address);

    esp_ota_handle_t update_handle = 0;
    esp_err_t err = esp_ota_begin(update_partition, OTA_SIZE_UNKNOWN, &update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_begin failed (%s)", esp_err_to_name(err));
        return false;
    }

    auto http = SetupHttp();
    if (!http->Open("GET", firmware_url)) {
        ESP_LOGE(TAG, "Failed to open HTTP connection to %s", firmware_url.c_str());
        esp_ota_abort(update_handle);
        return false;
    }

    if (http->GetStatusCode() != 200) {
        ESP_LOGE(TAG, "HTTP GET failed, status code: %d", http->GetStatusCode());
        http->Close();
        esp_ota_abort(update_handle);
        return false;
    }

    size_t total_len = http->GetContentLength();
    if (total_len == 0) {
        ESP_LOGW(TAG, "Content-Length not provided; assuming dynamic length.");
    }

    constexpr size_t BUFFER_SIZE = 1024;
    std::vector<uint8_t> buffer(BUFFER_SIZE);
    size_t written = 0;
    uint32_t last_progress = 0;

    TickType_t start_time = xTaskGetTickCount();

    while (true) {
        ssize_t len = http->Read(buffer.data(), buffer.size());
        if (len < 0) {
            ESP_LOGE(TAG, "Error reading HTTP stream");
            http->Close();
            esp_ota_abort(update_handle);
            return false;
        }

        if (len == 0) {
            break; // End of stream
        }

        err = esp_ota_write(update_handle, buffer.data(), len);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "esp_ota_write failed (%s)", esp_err_to_name(err));
            http->Close();
            esp_ota_abort(update_handle);
            return false;
        }

        written += len;

        if (total_len > 0 && callback) {
            uint32_t progress = (written * 100) / total_len;
            if (progress != last_progress) {
                TickType_t elapsed_ticks = xTaskGetTickCount() - start_time;
                float elapsed_sec = static_cast<float>(elapsed_ticks) / configTICK_RATE_HZ;
                size_t speed_bps = elapsed_sec > 0 ? static_cast<size_t>(written / elapsed_sec) : 0;

                callback(static_cast<int>(progress), speed_bps);
                last_progress = progress;
            }
        }
    }

    http->Close();

    err = esp_ota_end(update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_end failed (%s)!", esp_err_to_name(err));
        return false;
    }

    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed (%s)!", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "OTA upgrade finished successfully. Reboot required.");
    return true;
}

