bool Ota::IsNewVersionAvailable(const std::string &currentVersion, const std::string &newVersion)
{
    // Handle empty versions
    if (currentVersion.empty() || newVersion.empty()) {
        return false;
    }

    // Parse version strings into components
    std::vector<int> currentParts;
    std::vector<int> newParts;

    // Parse current version
    std::stringstream currentStream(currentVersion);
    std::string segment;
    while (std::getline(currentStream, segment, '.')) {
        try {
            currentParts.push_back(std::stoi(segment));
        } catch (const std::exception&) {
            currentParts.push_back(0);
        }
    }

    // Parse new version
    std::stringstream newStream(newVersion);
    while (std::getline(newStream, segment, '.')) {
        try {
            newParts.push_back(std::stoi(segment));
        } catch (const std::exception&) {
            newParts.push_back(0);
        }
    }

    // Compare version components from left to right
    size_t maxComponents = std::max(currentParts.size(), newParts.size());

    for (size_t i = 0; i < maxComponents; ++i) {
        int currentPart = (i < currentParts.size()) ? currentParts[i] : 0;
        int newPart = (i < newParts.size()) ? newParts[i] : 0;

        if (newPart > currentPart) {
            return true;  // New version is greater
        } else if (newPart < currentPart) {
            return false; // New version is smaller
        }
        // If equal, continue to next component
    }

    // Versions are identical
    return false;
}

