void SystemInfo::PrintTaskCpuUsage(TickType_t delay_ticks)
{
    TaskStatus_t* start_array = nullptr;
    TaskStatus_t* end_array = nullptr;
    UBaseType_t start_array_size, end_array_size;
    uint32_t start_run_time, end_run_time;
    uint32_t total_elapsed_time;
    esp_err_t ret = ESP_FAIL;

    // Allocate arrays for task status
    start_array_size = uxTaskGetNumberOfTasks();
    start_array = static_cast<TaskStatus_t*>(malloc(start_array_size * sizeof(TaskStatus_t)));
    if (start_array == nullptr)
    {
        ESP_LOGE(TAG, "Failed to allocate memory for start array");
        return;
    }

    // Get initial snapshot
    start_array_size = uxTaskGetSystemState(start_array, start_array_size, &start_run_time);

    if (start_array_size == 0)
    {
        ESP_LOGE(TAG, "Invalid size returned from first uxTaskGetSystemState()");
        free(start_array);
        return;
    }

    // Delay for given tick count
    vTaskDelay(delay_ticks);

    // Allocate space for second capture
    end_array_size = uxTaskGetNumberOfTasks();
    end_array = static_cast<TaskStatus_t*>(malloc(end_array_size * sizeof(TaskStatus_t)));
    if (end_array == nullptr)
    {
        ESP_LOGE(TAG, "Failed to allocate memory for end array");
        free(start_array);
        return;
    }

    // Take second snapshot
    end_array_size = uxTaskGetSystemState(end_array, end_array_size, &end_run_time);

    if (end_array_size == 0)
    {
        ESP_LOGE(TAG, "Invalid size returned from second uxTaskGetSystemState()");
        ret = ESP_ERR_INVALID_SIZE;
        goto cleanup;
    }

    // Compute total elapsed time
    total_elapsed_time = (end_run_time - start_run_time);
    if (total_elapsed_time == 0)
    {
        ESP_LOGW(TAG, "Total elapsed time is zero, cannot compute percentages.");
        ret = ESP_ERR_INVALID_STATE;
        goto cleanup;
    }

    // Print header
    ESP_LOGI(TAG, "| %-16s | %10s | %8s |", "Task Name", "Run Time", "Percent");

    // Compare tasks between two snapshots
    for (UBaseType_t i = 0; i < start_array_size; ++i)
    {
        int match_index = -1;
        for (UBaseType_t j = 0; j < end_array_size; ++j)
        {
            if (start_array[i].xHandle == end_array[j].xHandle)
            {
                match_index = j;
                end_array[j].xHandle = NULL; // Mark as matched
                break;
            }
        }

        if (match_index >= 0)
        {
            uint32_t task_elapsed_time =
                end_array[match_index].ulRunTimeCounter - start_array[i].ulRunTimeCounter;

            uint32_t percentage_time =
                (static_cast<uint64_t>(task_elapsed_time) * 100) /
                (total_elapsed_time * CONFIG_FREERTOS_NUMBER_OF_CORES);

            ESP_LOGI(TAG, "| %-16s | %10lu | %7lu%% |",
                     start_array[i].pcTaskName,
                     task_elapsed_time,
                     percentage_time);
        }
        else
        {
            // Task deleted during interval
            ESP_LOGI(TAG, "| %-16s | %10s | %8s |", start_array[i].pcTaskName, "Deleted", "--");
        }
    }

    // Show newly created tasks
    for (UBaseType_t i = 0; i < end_array_size; ++i)
    {
        if (end_array[i].xHandle != NULL)
        {
            ESP_LOGI(TAG, "| %-16s | %10s | %8s |", end_array[i].pcTaskName, "Created", "--");
        }
    }

    ret = ESP_OK;

cleanup:
    free(start_array);
    free(end_array);

    if (ret != ESP_OK)
    {
        ESP_LOGE(TAG, "Error occurred while computing task CPU usage.");
    }
}

void SystemInfo::PrintTaskList()
{
#define TASK_LIST_ARRAY_SIZE_OFFSET 5

    TaskStatus_t *task_status_array;
    UBaseType_t num_tasks;
    UBaseType_t array_size;

    // Determine number of tasks and allocate space for task status info
    array_size = uxTaskGetNumberOfTasks() + TASK_LIST_ARRAY_SIZE_OFFSET;
    task_status_array = (TaskStatus_t *)malloc(array_size * sizeof(TaskStatus_t));
    if (task_status_array == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for task list");
        return;
    }

    // Populate the array with task states
    num_tasks = uxTaskGetSystemState(task_status_array, array_size, NULL);
    if (num_tasks > array_size) {
        ESP_LOGW(TAG, "Truncated task list as more tasks exist than buffer allows.");
        num_tasks = array_size;
    }

    // Print header
    printf("Task List:\n");
    printf("| %-16s | %-9s | %-7s | %-10s | %-6s |\n", "Name", "State", "Pri", "StackWater", "Core");

    for (UBaseType_t i = 0; i < num_tasks; i++) {
        const char* state_str;

        switch (task_status_array[i].eCurrentState) {
            case eRunning:   state_str = "Running";   break;
            case eReady:     state_str = "Ready";     break;
            case eBlocked:   state_str = "Blocked";   break;
            case eSuspended: state_str = "Suspended"; break;
            case eDeleted:   state_str = "Deleted";   break;
            default:         state_str = "Unknown";   break;
        }

        printf("| %-16s | %-9s | %7lu | %10lu | %6ld |\n",
               task_status_array[i].pcTaskName,
               state_str,
               (unsigned long)task_status_array[i].uxCurrentPriority,
               (unsigned long)task_status_array[i].usStackHighWaterMark,
#if CONFIG_FREERTOS_NUMBER_OF_CORES > 1
               (long)task_status_array[i].xCoreID
#else
               -1L
#endif
              );
    }

    free(task_status_array);
}

