### Completed Constructor Implementation

Here's how you could implement the full constructor logic inside its body:

```cpp
#include "audio_debugger.h"
#include "sdkconfig.h"

#if CONFIG_USE_AUDIO_DEBUGGER
#include <esp_log.h>
#include <arpa/inet.h>
#include <unistd.h>
#include <errno.h>
#include <cstring>
#include <string>
#endif

#define TAG "AudioDebugger"

AudioDebugger::AudioDebugger()
{
#if CONFIG_USE_AUDIO_DEBUGGER
    udp_sockfd_ = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (udp_sockfd_ < 0)
    {
        ESP_LOGE(TAG, "Failed to create UDP socket: %d", errno);
        return;
    }

    memset(&udp_server_addr_, 0, sizeof(udp_server_addr_));
    udp_server_addr_.sin_family = AF_INET;
    udp_server_addr_.sin_port = htons(CONFIG_AUDIO_DEBUG_PORT);

    if (inet_aton(CONFIG_AUDIO_DEBUG_UDP_SERVER, &udp_server_addr_.sin_addr) == 0)
    {
        ESP_LOGE(TAG, "Invalid IP address: %s", CONFIG_AUDIO_DEBUG_UDP_SERVER);
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        return;
    }

    ESP_LOGI(TAG, "Initialized UDP debugger to %s:%d", CONFIG_AUDIO_DEBUG_UDP_SERVER, CONFIG_AUDIO_DEBUG_PORT);
#else
    // If not enabled, explicitly set to invalid state
    udp_sockfd_ = -1;
#endif
}

AudioDebugger::~AudioDebugger()
{
#if CONFIG_USE_AUDIO_DEBUGGER
    if (udp_sockfd_ >= 0)
    {
        close(udp_sockfd_);
        ESP_LOGI(TAG, "Closed UDP socket");
    }
#endif
}

void AudioDebugger::Feed(const std::vector<int16_t> &data)
{
#if CONFIG_USE_AUDIO_DEBUGGER
    if (udp_sockfd_ < 0 || data.empty()) {
        return;
    }

    const void* buffer = data.data();
    size_t length = data.size() * sizeof(int16_t);

    ssize_t sent_bytes = sendto(
        udp_sockfd_,
        buffer,
        length,
        0,
        reinterpret_cast<const struct sockaddr*>(&udp_server_addr_),
        sizeof(udp_server_addr_)
    );

    if (sent_bytes < 0) {
        ESP_LOGW(TAG, "Failed to send audio data: errno %d", errno);
    } else if (static_cast<size_t>(sent_bytes) != length) {
        ESP_LOGW(TAG, "Incomplete send: expected %zu bytes, sent %zd bytes", length, sent_bytes);
    }
#endif
}

