bool AfeWakeWord::Initialize(AudioCodec* codec, srmodel_list_t* models)
{
    codec_ = codec;
    models_ = models;

    // Determine reference channels count
    int ref_num = codec_->input_reference() ? 1 : 0;

    // Build input format string
    std::string input_format;
    for (int i = 0; i < codec_->input_channels() - ref_num; i++)
    {
        input_format.push_back('M'); // Microphone channels
    }
    for (int i = 0; i < ref_num; i++)
    {
        input_format.push_back('R'); // Reference channels
    }

    // Initialize AFE configuration
    afe_config_t* afe_config = afe_config_init(input_format.c_str(), models_, AFE_TYPE_SR, AFE_MODE_HIGH_PERF);
    if (!afe_config) {
        ESP_LOGE(TAG, "Failed to initialize AFE config");
        return false;
    }

    // Configure AFE parameters
    afe_config->aec_init = codec_->input_reference();
    afe_config->aec_mode = AEC_MODE_SR_HIGH_PERF;
    afe_config->afe_perferred_core = 1;
    afe_config->afe_perferred_priority = 1;
    afe_config->memory_alloc_mode = AFE_MEMORY_ALLOC_MORE_PSRAM;

    // Create AFE interface and data handle
    afe_iface_ = esp_afe_handle_from_config(afe_config);
    if (!afe_iface_) {
        ESP_LOGE(TAG, "Failed to get AFE handle");
        return false;
    }

    afe_data_ = afe_iface_->create_from_config(afe_config);
    if (!afe_data_) {
        ESP_LOGE(TAG, "Failed to create AFE data");
        return false;
    }

    // Start audio detection task
    BaseType_t result = xTaskCreate([](void* arg)
    {
        auto this_ = (AfeWakeWord*)arg;
        this_->AudioDetectionTask();
        vTaskDelete(NULL);
    }, "audio_detection", 4096, this, 3, nullptr);

    if (result != pdPASS) {
        ESP_LOGE(TAG, "Failed to create audio detection task");
        return false;
    }

    ESP_LOGI(TAG, "AFE Wake Word initialized successfully");
    return true;
}

