void AfeWakeWord::StoreWakeWordData(const int16_t *data, size_t samples)
{
    // Create a local copy of the incoming audio data
    std::vector<int16_t> buffer(data, data + samples);

    // Lock mutex to safely modify wake_word_pcm_
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Push new data to back of deque
    wake_word_pcm_.emplace_back(std::move(buffer));

    // Limit total buffers to prevent unbounded growth
    if (wake_word_pcm_.size() > MAX_WAKE_WORD_PCM_BUFFERS) {
        wake_word_pcm_.pop_front();
    }
}

void AfeWakeWord::EncodeWakeWordData()
{
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    if (wake_word_pcm_.empty()) {
        return;
    }

    // Flatten all stored PCM data into a single vector
    size_t total_samples = 0;
    for (const auto& chunk : wake_word_pcm_) {
        total_samples += chunk.size();
    }

    std::vector<int16_t> pcm_data;
    pcm_data.reserve(total_samples);
    for (const auto& chunk : wake_word_pcm_) {
        pcm_data.insert(pcm_data.end(), chunk.begin(), chunk.end());
    }

    // Clear the PCM storage after copying
    wake_word_pcm_.clear();

    // Placeholder for actual OPUS encoding
    // In real scenario, you'd call libopus or equivalent API here
    std::vector<uint8_t> opus_encoded_data;

    // Simulate encoding process
    // Replace this block with real OPUS encoding logic
    const size_t frame_size = 960; // e.g., 30ms @ 16kHz
    const size_t bytes_per_frame = 64; // typical estimate for OPUS at low bitrate

    size_t num_frames = (pcm_data.size() + frame_size - 1) / frame_size;

    for (size_t i = 0; i < num_frames; ++i) {
        size_t start = i * frame_size;
        size_t end = std::min(start + frame_size, pcm_data.size());
        // Dummy encoding step
        for (size_t j = start; j < end; ++j) {
            // Convert each sample to two bytes (simulate encoding)
            int16_t sample = pcm_data[j];
            opus_encoded_data.push_back(static_cast<uint8_t>(sample & 0xFF));
            opus_encoded_data.push_back(static_cast<uint8_t>((sample >> 8) & 0xFF));
        }
    }

    // Push encoded packet(s) to opus queue
    wake_word_opus_.emplace_back(std::move(opus_encoded_data));

    // Notify any waiting consumers
    wake_word_cv_.notify_one();
}

bool AfeWakeWord::GetWakeWordOpus(std::vector<uint8_t> &opus)
{
    std::unique_lock<std::mutex> lock(wake_word_mutex_);

    // Wait until we have at least one element or the end marker
    wake_word_cv_.wait(lock, [this] { return !wake_word_opus_.empty(); });

    // Move the first encoded packet out
    opus = std::move(wake_word_opus_.front());
    wake_word_opus_.pop_front();

    // Check for end marker (an empty vector signals completion)
    if (opus.empty()) {
        return false;
    }

    return true;
}

