void CustomWakeWord::ParseWakenetModelConfig()
{
    const char *config_json = Assets::GetInstance()->GetContent("wakeword_config.json");
    if (!config_json) {
        ESP_LOGE(TAG, "Failed to load wakeword_config.json");
        return;
    }

    cJSON *root = cJSON_Parse(config_json);
    if (!root) {
        ESP_LOGE(TAG, "Failed to parse wakeword_config.json");
        return;
    }

    cJSON *lang_item = cJSON_GetObjectItem(root, "language");
    if (lang_item && cJSON_IsString(lang_item)) {
        language_ = lang_item->valuestring;
    } else {
        language_ = "en"; // default fallback
    }

    cJSON *duration_item = cJSON_GetObjectItem(root, "duration_ms");
    if (duration_item && cJSON_IsNumber(duration_item)) {
        duration_ = duration_item->valueint;
    } else {
        duration_ = 5000; // default 5s
    }

    cJSON *threshold_item = cJSON_GetObjectItem(root, "threshold");
    if (threshold_item && cJSON_IsNumber(threshold_item)) {
        threshold_ = static_cast<float>(threshold_item->valuedouble);
    } else {
        threshold_ = 0.6f; // default value
    }

    cJSON *commands_array = cJSON_GetObjectItem(root, "commands");
    if (commands_array && cJSON_IsArray(commands_array)) {
        commands_.clear();
        int cmd_count = cJSON_GetArraySize(commands_array);
        for (int i = 0; i < cmd_count; ++i) {
            cJSON *cmd_obj = cJSON_GetArrayItem(commands_array, i);
            if (!cmd_obj) continue;

            cJSON *id_item = cJSON_GetObjectItem(cmd_obj, "id");
            cJSON *command_item = cJSON_GetObjectItem(cmd_obj, "command");
            cJSON *text_item = cJSON_GetObjectItem(cmd_obj, "text");
            cJSON *action_item = cJSON_GetObjectItem(cmd_obj, "action");

            if (command_item && text_item && action_item &&
                cJSON_IsString(command_item) &&
                cJSON_IsString(text_item) &&
                cJSON_IsString(action_item)) {

                Command cmd;
                cmd.id = id_item ? id_item->valueint : (i + 1);
                cmd.command = command_item->valuestring;
                cmd.text = text_item->valuestring;
                cmd.action = action_item->valuestring;

                commands_.push_back(std::move(cmd));
            } else {
                ESP_LOGW(TAG, "Skipping invalid command entry at index %d", i);
            }
        }
    } else {
        ESP_LOGW(TAG, "No valid 'commands' array found in config.");
    }

    cJSON_Delete(root);

    ESP_LOGI(TAG, "Parsed wakeword config: language=%s, duration=%d ms, threshold=%.2f",
             language_.c_str(), duration_, threshold_);
}
