```cpp
void CustomWakeWord::StoreWakeWordData(const std::vector<int16_t> &data)
{
    // Optional: Define maximum number of buffered chunks to prevent memory overflow
    static constexpr size_t kMaxPcmBuffers = 100;

    // Lock before accessing shared resource
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Add new PCM data chunk
    wake_word_pcm_.emplace_back(data);

    // Prevent unbounded memory use by dropping oldest entries if necessary
    while (wake_word_pcm_.size() > kMaxPcmBuffers) {
        wake_word_pcm_.pop_front();
    }
}

void CustomWakeWord::EncodeWakeWordData()
{
    if (codec_ == nullptr || wake_word_pcm_.empty()) {
        return;
    }

    // Flatten the deque of PCM chunks into a single vector
    std::vector<int16_t> pcm_data;
    size_t total_samples = 0;
    for (const auto& chunk : wake_word_pcm_) {
        total_samples += chunk.size();
    }
    pcm_data.reserve(total_samples);

    for (const auto& chunk : wake_word_pcm_) {
        pcm_data.insert(pcm_data.end(), chunk.begin(), chunk.end());
    }

    // Encode PCM to Opus using the codec
    std::vector<uint8_t> opus_packet = codec_->encode(pcm_data);

    // Lock mutex before modifying shared queue
    {
        std::lock_guard<std::mutex> lock(wake_word_mutex_);
        wake_word_opus_.emplace_back(std::move(opus_packet));
    }

    // Notify any thread waiting for new Opus data
    wake_word_cv_.notify_one();

    // Clear the PCM buffer as it's now processed
    wake_word_pcm_.clear();
}

bool CustomWakeWord::GetWakeWordOpus(std::vector<uint8_t> &opus)
{
    std::unique_lock<std::mutex> lock(wake_word_mutex_);

    // Wait until there is data available or the queue is not empty
    wake_word_cv_.wait(lock, [this]() { return !wake_word_opus_.empty(); });

    // Move the first element from the deque to output parameter
    opus = std::move(wake_word_opus_.front());
    wake_word_opus_.pop_front();

    // If the returned packet is empty, it indicates end of stream
    return !opus.empty();
}

void XL9555::SetOutputState(uint8_t bit, uint8_t level)
{
    if (bit > 15) {
        ESP_LOGE(TAG, "Invalid bit index %d. Must be between 0 and 15.", bit);
        return;
    }

    uint8_t reg_addr;
    uint8_t index = bit;

    // Select appropriate register and adjust index accordingly
    if (bit < 8) {
        reg_addr = 0x02;  // Port 0
    } else {
        reg_addr = 0x03;  // Port 1
        index -= 8;
    }

    // Read current state of the register
    uint8_t data = ReadReg(reg_addr);

    // Update the specific bit
    data = (data & ~(1 << index)) | ((level & 0x01) << index);

    // Write modified data back to the register
    WriteReg(reg_addr, data);
}

