bool AudioDataBuffer::ProcessProbabilityData(const std::vector<float> &probabilities, float threshold)
{
    for (float prob : probabilities)
    {
        // Convert probability to bit based on threshold
        uint8_t bit = (prob >= threshold) ? 1 : 0;

        switch (current_state_)
        {
        case DataReceptionState::kInactive:
        {
            // Maintain identifier buffer for pattern matching
            identifier_buffer_.push_back(bit);
            if (identifier_buffer_.size() > identifier_buffer_size_)
            {
                identifier_buffer_.pop_front();
            }

            // Try to match Start of Transmission pattern
            if (identifier_buffer_.size() == start_of_transmission_.size() &&
                std::equal(identifier_buffer_.begin(), identifier_buffer_.end(),
                           start_of_transmission_.begin()))
            {
                ESP_LOGD(kLogTag, "Detected Start of Transmission");
                current_state_ = DataReceptionState::kReceiving;
                bit_buffer_.clear();
                identifier_buffer_.clear();
            }
            break;
        }
        case DataReceptionState::kReceiving:
        {
            // Accumulate data bits
            bit_buffer_.push_back(bit);

            // Prevent overflow beyond maximum allowed size
            if (bit_buffer_.size() > max_bit_buffer_size_)
            {
                ESP_LOGW(kLogTag, "Bit buffer overflow, resetting");
                current_state_ = DataReceptionState::kInactive;
                ClearBuffers();
                break;
            }

            // Maintain identifier buffer to check for End of Transmission
            identifier_buffer_.push_back(bit);
            if (identifier_buffer_.size() > identifier_buffer_size_)
            {
                identifier_buffer_.pop_front();
            }

            // Try to match End of Transmission pattern
            if (identifier_buffer_.size() == end_of_transmission_.size() &&
                std::equal(identifier_buffer_.begin(), identifier_buffer_.end(),
                           end_of_transmission_.begin()))
            {
                ESP_LOGD(kLogTag, "Detected End of Transmission");

                // Remove trailing identifier bits from bit_buffer_
                for (size_t i = 0; i < end_of_transmission_.size(); ++i)
                {
                    if (!bit_buffer_.empty())
                        bit_buffer_.pop_back();
                }

                // Convert bits to bytes
                auto bytes = ConvertBitsToBytes(bit_buffer_);

                // Extract content and optional checksum
                if (bytes.empty())
                {
                    ESP_LOGE(kLogTag, "No data received");
                    current_state_ = DataReceptionState::kInactive;
                    ClearBuffers();
                    break;
                }

                std::string received_text(bytes.begin(), bytes.end());

                // Handle possible null terminators at end
                size_t null_pos = received_text.find('\0');
                if (null_pos != std::string::npos)
                {
                    received_text.erase(null_pos);
                }

                // Optional checksum validation
                if (enable_checksum_validation_ && received_text.length() > 1)
                {
                    uint8_t received_checksum = static_cast<uint8_t>(received_text.back());
                    std::string data_part = received_text.substr(0, received_text.length() - 1);
                    uint8_t calculated_checksum = CalculateChecksum(data_part);

                    if (calculated_checksum != received_checksum)
                    {
                        ESP_LOGW(kLogTag, "Checksum mismatch: expected %u, got %u",
                                 calculated_checksum, received_checksum);
                        current_state_ = DataReceptionState::kInactive;
                        ClearBuffers();
                        break;
                    }

                    decoded_text = data_part;
                }
                else
                {
                    decoded_text = received_text;
                }

                ESP_LOGI(kLogTag, "Successfully decoded data: %s", decoded_text->c_str());

                current_state_ = DataReceptionState::kInactive;
                ClearBuffers();

                return true; // Indicate successful completion
            }
            break;
        }
        default:
            break;
        }
    }

    return false; // No complete frame yet
}

std::vector<uint8_t> AudioDataBuffer::ConvertBitsToBytes(const std::vector<uint8_t> &bits) const
{
    std::vector<uint8_t> bytes;
    if (bits.empty()) {
        return bytes;
    }

    size_t num_bits = bits.size();
    size_t num_bytes = (num_bits + 7) / 8; // Round up division to get total bytes needed
    bytes.reserve(num_bytes);

    for (size_t i = 0; i < num_bits; i += 8) {
        uint8_t byte = 0;
        for (size_t j = 0; j < 8 && (i + j) < num_bits; ++j) {
            // Assuming LSB is sent first (bit 0 corresponds to 2^0)
            if (bits[i + j]) {
                byte |= (1 << j);
            }
        }
        bytes.push_back(byte);
    }

    return bytes;
}

