void Backlight::SetBrightness(uint8_t brightness, bool save)
{
    // Clamp brightness to valid range [0, 100]
    if (brightness > 100)
        brightness = 100;

    // Save brightness setting if requested
    if (save)
    {
        Settings settings("display", false);
        settings.SetInt("brightness", brightness);
    }

    // If already at target, do nothing
    if (brightness_ == brightness)
        return;

    target_brightness_ = brightness;

    // Calculate step size and direction for smooth transition
    int16_t diff = static_cast<int16_t>(target_brightness_) - static_cast<int16_t>(brightness_);
    uint32_t duration_ms = 300; // Total fade time in milliseconds
    uint32_t interval_ms = 5;   // Timer interval in ms
    int32_t steps = duration_ms / interval_ms;

    if (steps <= 0)
        steps = 1;

    step_ = diff / steps;

    // Ensure step is at least +/-1 to guarantee progress
    if (step_ == 0)
    {
        step_ = (diff > 0) ? 1 : -1;
    }

    // Stop previous timer if running
    esp_timer_stop(transition_timer_);

    // Start transition timer
    esp_timer_start_periodic(transition_timer_, 5 * 1000); // 5ms in microseconds

    ESP_LOGI(TAG, "Set brightness to %d", brightness);
}

