SingleLed::SingleLed(gpio_num_t gpio) : r_(0), g_(0), b_(0), blink_counter_(0), blink_interval_ms_(0)
{
    // Configure LED Strip
    led_strip_config_t strip_config = {};
    strip_config.strip_gpio_num = gpio;
    strip_config.max_leds = 1;       // Assuming only one LED
    strip_config.led_pixel_format = LED_PIXEL_FORMAT_GRB;
    strip_config.led_model = LED_MODEL_WS2812;

    led_strip_rmt_config_t rmt_config = {};
    rmt_config.rmt_channel = RMT_CHANNEL_0;
    rmt_config.clk_src = RMT_CLK_SRC_DEFAULT;
    rmt_config.resolution_hz = 10 * 1000 * 1000; // 10MHz resolution
    rmt_config.mem_block_symbols = 64;
    rmt_config.flags.with_dma = false;

    esp_err_t err = led_strip_new_rmt_device(&strip_config, &rmt_config, &led_strip_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize LED strip on GPIO %d", gpio);
        led_strip_ = nullptr;
        return;
    }

    // Clear the LED initially
    led_strip_clear(led_strip_);

    // Initialize mutex
    mutex_ = std::make_unique<std::mutex>();

    // Create blink timer
    esp_timer_create_args_t timer_args = {};
    timer_args.callback = &blink_timer_callback;
    timer_args.arg = this;
    timer_args.dispatch_method = ESP_TIMER_TASK;
    timer_args.name = "led_blink_timer";

    esp_timer_create(&timer_args, &blink_timer_);
