void SingleLed::StartBlinkTask(int times, int interval_ms)
{
    if (led_strip_ == nullptr)
    {
        return;
    }

    std::lock_guard<std::mutex> lock(mutex_);

    // Stop any existing timer
    esp_timer_stop(blink_timer_);

    // Set blink count: -1 for infinite, otherwise double the number of visible blinks
    blink_counter_ = (times == BLINK_INFINITE) ? BLINK_INFINITE : times * 2;

    // If times is 0 or negative (but not -1), do nothing
    if (times == 0 || (times < 0 && times != BLINK_INFINITE))
    {
        return;
    }

    // Start the periodic timer
    ESP_ERROR_CHECK(esp_timer_start_periodic(blink_timer_, interval_ms * 1000ULL));
}

void SingleLed::OnBlinkTimer()
{
    if (led_strip_ == nullptr)
    {
        return;
    }

    std::lock_guard<std::mutex> lock(mutex_);

    if (blink_counter_ == 0 && blink_counter_ != BLINK_INFINITE)
    {
        esp_timer_stop(blink_timer_);
        return;
    }

    bool is_on = (blink_counter_ % 2) == 0;

    if (is_on)
    {
        led_strip_set_pixel(led_strip_, 0, r_, g_, b_);
    }
    else
    {
        led_strip_clear(led_strip_);
    }

    led_strip_refresh(led_strip_);

    if (blink_counter_ != BLINK_INFINITE)
    {
        --blink_counter_;
    }
}

