bool MqttProtocol::StartMqttClient(bool report_error)
{
    auto &app = Application::GetInstance();
    auto settings = app.GetSettings();

    if (!settings->network.mqtt.enable)
    {
        ESP_LOGI(TAG, "MQTT is disabled in settings");
        return false;
    }

    // Check if already connected
    if (mqtt_ != nullptr && mqtt_->IsConnected())
    {
        ESP_LOGI(TAG, "MQTT client is already connected");
        return true;
    }

    // Reset error state
    error_occurred_ = false;

    // Create MQTT client if needed
    if (mqtt_ == nullptr)
    {
        auto network = Board::GetInstance().GetNetwork();
        mqtt_ = network->CreateMqtt();
        if (mqtt_ == nullptr)
        {
            ESP_LOGE(TAG, "Failed to create MQTT client");
            if (report_error)
            {
                SetError(Lang::Strings::SERVER_ERROR);
            }
            return false;
        }

        // Set up callbacks
        mqtt_->OnConnected([this]()
        {
            ESP_LOGI(TAG, "MQTT connected");
            xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_CONNECTED_EVENT);
        });

        mqtt_->OnDisconnected([this]()
        {
            ESP_LOGI(TAG, "MQTT disconnected");
            xEventGroupClearBits(event_group_handle_, MQTT_PROTOCOL_CONNECTED_EVENT);

            // Schedule reconnection if still alive
            if (*alive_)
            {
                esp_timer_start_once(reconnect_timer_, 5000000); // 5 seconds
            }
        });

        mqtt_->OnMessage([this](const std::string &topic, const std::string &payload)
        {
            HandleMqttMessage(topic, payload);
        });
    }

    // Configure MQTT client
    MqttConfig config;
    config.host = settings->network.mqtt.host;
    config.port = settings->network.mqtt.port;
    config.username = settings->network.mqtt.username;
    config.password = settings->network.mqtt.password;
    config.client_id = settings->network.mqtt.client_id.empty() ? 
                       ("xiaozhi_" + Board::GetInstance().GetDeviceId()) : 
                       settings->network.mqtt.client_id;

    // Set last will
    config.will.topic = settings->network.mqtt.prefix + "/state";
    config.will.payload = "offline";
    config.will.qos = 1;
    config.will.retain = true;

    mqtt_->Configure(config);

    // Set topics
    publish_topic_ = settings->network.mqtt.prefix + "/from_client";
    subscribe_topic_ = settings->network.mqtt.prefix + "/to_client";

    // Connect
    if (!mqtt_->Connect())
    {
        ESP_LOGE(TAG, "Failed to connect to MQTT broker");
        if (report_error)
        {
            SetError(Lang::Strings::SERVER_ERROR);
        }
        return false;
    }

    // Wait for connection
    EventBits_t bits = xEventGroupWaitBits(
        event_group_handle_, 
        MQTT_PROTOCOL_CONNECTED_EVENT, 
        pdFALSE, 
        pdFALSE, 
        pdMS_TO_TICKS(10000)
    );

    if (!(bits & MQTT_PROTOCOL_CONNECTED_EVENT))
    {
        ESP_LOGE(TAG, "MQTT connection timeout");
        if (report_error)
        {
            SetError(Lang::Strings::SERVER_TIMEOUT);
        }
        return false;
    }

    // Subscribe to topic
    if (!mqtt_->Subscribe(subscribe_topic_, 1))
    {
        ESP_LOGE(TAG, "Failed to subscribe to topic: %s", subscribe_topic_.c_str());
        if (report_error)
        {
            SetError(Lang::Strings::SERVER_ERROR);
        }
        return false;
    }

    ESP_LOGI(TAG, "MQTT client started successfully");
    return true;
}

