bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (!IsAudioChannelOpened()) {
        ESP_LOGE(TAG, "Audio channel is not opened");
        return false;
    }

    if (packet == nullptr || packet->payload.empty()) {
        ESP_LOGE(TAG, "Invalid audio packet");
        return false;
    }

    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Prepare UDP packet header
    /*
     * UDP Encrypted OPUS Packet Format:
     * |type 1u|flags 1u|payload_len 2u|ssrc 4u|timestamp 4u|sequence 4u|
     * |payload payload_len|
     */

    uint16_t payload_len = packet->payload.size();
    uint32_t ssrc = htonl(0x12345678); // Fixed SSRC
    uint32_t timestamp = htonl(packet->timestamp);
    uint32_t sequence = htonl(++local_sequence_);

    // Create plaintext packet with header
    std::vector<uint8_t> plaintext(sizeof(uint8_t) + sizeof(uint8_t) + sizeof(uint16_t) + 
                                   sizeof(uint32_t) + sizeof(uint32_t) + sizeof(uint32_t) + payload_len);

    size_t offset = 0;

    // Type (0x01 for audio data)
    plaintext[offset++] = 0x01;

    // Flags (0x00)
    plaintext[offset++] = 0x00;

    // Payload length (network byte order)
    uint16_t net_payload_len = htons(payload_len);
    memcpy(plaintext.data() + offset, &net_payload_len, sizeof(uint16_t));
    offset += sizeof(uint16_t);

    // SSRC
    memcpy(plaintext.data() + offset, &ssrc, sizeof(uint32_t));
    offset += sizeof(uint32_t);

    // Timestamp
    memcpy(plaintext.data() + offset, &timestamp, sizeof(uint32_t));
    offset += sizeof(uint32_t);

    // Sequence number
    memcpy(plaintext.data() + offset, &sequence, sizeof(uint32_t));
    offset += sizeof(uint32_t);

    // Payload
    memcpy(plaintext.data() + offset, packet->payload.data(), payload_len);

    // Encrypt the packet
    size_t encrypted_size = plaintext.size();
    std::vector<uint8_t> encrypted_packet(aes_nonce_.size() + encrypted_size);

    // Copy nonce to the beginning of the packet
    memcpy(encrypted_packet.data(), aes_nonce_.data(), aes_nonce_.size());

    // Encrypt the plaintext
    size_t nc_off = 0;
    uint8_t stream_block[16] = {0};
    int ret = mbedtls_aes_crypt_ctr(&aes_ctx_, encrypted_size, &nc_off, 
                                    (uint8_t*)aes_nonce_.data(), stream_block,
                                    plaintext.data(), 
                                    encrypted_packet.data() + aes_nonce_.size());

    if (ret != 0) {
        ESP_LOGE(TAG, "Failed to encrypt audio data, ret: %d", ret);
        return false;
    }

    // Send the encrypted packet
    if (!udp_->Send((char*)encrypted_packet.data(), encrypted_packet.size())) {
        ESP_LOGE(TAG, "Failed to send audio packet");
        return false;
    }

    last_incoming_time_ = std::chrono::steady_clock::now();
    return true;
}

