void MqttProtocol::ParseServerHello(const cJSON *root)
{
    // Ensure all necessary fields are present
    cJSON *session_id_item = cJSON_GetObjectItem(root, "session_id");
    cJSON *udp_server_item = cJSON_GetObjectItem(root, "udp_server");
    cJSON *udp_port_item = cJSON_GetObjectItem(root, "udp_port");
    cJSON *key_item = cJSON_GetObjectItem(root, "key");
    cJSON *nonce_item = cJSON_GetObjectItem(root, "nonce");

    if (!cJSON_IsString(session_id_item) ||
        !cJSON_IsString(udp_server_item) ||
        !cJSON_IsNumber(udp_port_item) ||
        !cJSON_IsString(key_item) ||
        !cJSON_IsString(nonce_item))
    {
        ESP_LOGE(TAG, "Invalid server hello message format");
        SetError(Lang::Strings::INVALID_MESSAGE_FORMAT);
        return;
    }

    // Save session info
    session_id_ = session_id_item->valuestring;
    udp_server_ = udp_server_item->valuestring;
    udp_port_ = udp_port_item->valueint;

    // Decode hex-encoded key and nonce
    std::string key_hex = key_item->valuestring;
    std::string nonce_hex = nonce_item->valuestring;

    std::string key = DecodeHexString(key_hex);
    aes_nonce_ = DecodeHexString(nonce_hex);

    // Validate lengths
    if (key.size() != 16 || aes_nonce_.size() != 16)
    {
        ESP_LOGE(TAG, "Invalid key or nonce length");
        SetError(Lang::Strings::INVALID_CRYPTO_PARAMS);
        return;
    }

    // Initialize AES context with received key
    mbedtls_aes_init(&aes_ctx_);
    if (mbedtls_aes_setkey_enc(&aes_ctx_, reinterpret_cast<const unsigned char*>(key.data()), 128) != 0)
    {
        ESP_LOGE(TAG, "Failed to set AES key");
        SetError(Lang::Strings::CRYPTO_INIT_FAILED);
        return;
    }

    // Reset sequence counters
    local_sequence_ = 0;
    remote_sequence_ = 0;

    // Signal that we've successfully received the server hello
    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);

    ESP_LOGI(TAG, "Server hello received, session_id=%s, udp=%s:%d",
             session_id_.c_str(), udp_server_.c_str(), udp_port_);
}

static inline uint8_t CharToHex(char c)
{
    if (c >= '0' && c <= '9') {
        return static_cast<uint8_t>(c - '0');
    }
    if (c >= 'A' && c <= 'F') {
        return static_cast<uint8_t>(c - 'A' + 10);
    }
    if (c >= 'a' && c <= 'f') {
        return static_cast<uint8_t>(c - 'a' + 10);
    }
    // Return 0 for invalid hex characters
    return 0;
}

std::string MqttProtocol::DecodeHexString(const std::string &hex_string)
{
    std::string decoded;
    decoded.reserve(hex_string.size() / 2);
    for (size_t i = 0; i < hex_string.size(); i += 2)
    {
        char high_char = hex_string[i];
        char low_char = hex_string[i + 1];

        uint8_t high_nibble = CharToHex(high_char);
        uint8_t low_nibble = CharToHex(low_char);

        char byte = (high_nibble << 4) | low_nibble;
        decoded.push_back(byte);
    }
    return decoded;
}

