bool WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (websocket_ == nullptr || !websocket_->IsConnected())
    {
        ESP_LOGE(TAG, "WebSocket not connected");
        return false;
    }

    if (packet == nullptr || packet->payload.empty())
    {
        ESP_LOGW(TAG, "Empty audio packet provided");
        return false;
    }

    const uint8_t* payload_data = packet->payload.data();
    size_t payload_size = packet->payload.size();

    bool success = false;

    if (version_ == 2)
    {
        // Prepare BinaryProtocol2 header
        BinaryProtocol2 bp2_header{};
        bp2_header.version = htons(2);
        bp2_header.type = htons(0); // Assuming type 0 for audio
        bp2_header.timestamp = htonl(packet->timestamp);
        bp2_header.payload_size = htonl(static_cast<uint32_t>(payload_size));

        std::vector<uint8_t> buffer(sizeof(BinaryProtocol2) + payload_size);
        memcpy(buffer.data(), &bp2_header, sizeof(BinaryProtocol2));
        memcpy(buffer.data() + sizeof(BinaryProtocol2), payload_data, payload_size);

        success = websocket_->Send(reinterpret_cast<const char*>(buffer.data()), buffer.size(), true); // true = binary
    }
    else if (version_ == 3)
    {
        // Prepare BinaryProtocol3 header
        BinaryProtocol3 bp3_header{};
        bp3_header.type = 0; // Assuming type 0 for audio
        bp3_header.payload_size = htons(static_cast<uint16_t>(payload_size));

        std::vector<uint8_t> buffer(sizeof(BinaryProtocol3) + payload_size);
        memcpy(buffer.data(), &bp3_header, sizeof(BinaryProtocol3));
        memcpy(buffer.data() + sizeof(BinaryProtocol3), payload_data, payload_size);

        success = websocket_->Send(reinterpret_cast<const char*>(buffer.data()), buffer.size(), true); // true = binary
    }
    else
    {
        // Default behavior: send raw payload
        success = websocket_->Send(reinterpret_cast<const char*>(payload_data), payload_size, true); // true = binary
    }

    if (!success)
    {
        ESP_LOGE(TAG, "Failed to send audio packet");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    return true;
}

